"use client";

import { useCallback, useState } from "react";
import { api } from "./api";
import { useAuthStore } from "@/store/authStore";

export interface FileItem {
  id: string;
  original_filename: string;
  file_type: string;
  mime_type: string;
  file_size: number;
  created_at: string;
  updated_at: string;
  storage_path?: string;
  source?: "supabase" | "media-server";
  ownerId?: string;
  visibility?: 'public' | 'private';
  sharedWith?: { userId: string; canEdit: boolean }[];
}

export interface UploadProgress {
  fileId: string;
  progress: number;
  status: "uploading" | "success" | "error";
  error?: string;
}

export interface FileStats {
  total_files: number;
  total_size: number;
  file_types: Record<string, number>;
  file_type_sizes?: Record<string, number>;
}

function getErrorMessage(error: unknown, fallback: string) {
  return error instanceof Error ? error.message : fallback;
}

export function useFileManager() {
  const currentUser = useAuthStore((s) => s.currentUser);
  const [files, setFiles] = useState<FileItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [stats, setStats] = useState<FileStats | null>(null);

  const loadFiles = useCallback(async (fileType?: string) => {
    try {
      setLoading(true);
      setError(null);
      
      let allFiles: FileItem[] = [];
      try {
        const msData = await api.mediaServer.listFiles(currentUser?.id, currentUser?.role, fileType);
        allFiles = msData.files.map((f: any) => ({
          id: f.fileId,
          original_filename: f.originalName,
          file_type: f.fileType,
          mime_type: f.mimeType,
          file_size: f.size,
          created_at: f.uploadedAt,
          updated_at: f.uploadedAt,
          storage_path: f.streamUrl,
          source: 'media-server',
          ownerId: f.ownerId,
          visibility: f.visibility,
          sharedWith: f.sharedWith
        }));
      } catch (err) {
        throw new Error("Failed to load local files. Is the media server running?");
      }

      // Sort by date descending
      allFiles.sort(
        (a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
      );
      
      setFiles(allFiles);
    } catch (err: unknown) {
      const errorMsg = getErrorMessage(err, "Failed to load files");
      setError(errorMsg);
      console.error("Failed to load files:", err);
    } finally {
      setLoading(false);
    }
  }, [currentUser?.id, currentUser?.role]);

  const uploadFile = useCallback(
    async (file: File) => {
      try {
        setError(null);
        // Fully use local backend for all sizes
        const response = await api.mediaServer.uploadFile(file, currentUser?.id);

        await new Promise((resolve) => setTimeout(resolve, 500));
        await loadFiles();

        return response;
      } catch (err: unknown) {
        const errorMsg = getErrorMessage(err, "Upload failed");
        setError(errorMsg);
        console.error("Upload error:", err);
        throw err;
      }
    },
    [loadFiles, currentUser?.id]
  );

  const downloadFile = useCallback(async (fileId: string, filename: string) => {
    try {
      setError(null);
      // Wait for the state or find in existing files
      // Because we don't have access to the latest files in this callback without dependency,
      // we can use a functional update or just rely on the files array if it's up to date.
      // But a better approach is to pass the source directly, or find it here.
      // Let's find it in the files array:
      const file = files.find(f => f.id === fileId);
      
      let url = api.mediaServer.streamUrl(fileId);

      const anchor = document.createElement("a");
      anchor.href = url;
      anchor.download = filename;

      document.body.appendChild(anchor);
      anchor.click();

      window.setTimeout(() => {
        document.body.removeChild(anchor);
      }, 100);
    } catch (err: unknown) {
      const errorMsg = getErrorMessage(err, "Download failed");
      setError(errorMsg);
      console.error("Download error:", err);
      throw err;
    }
  }, [files]);

  const deleteFile = useCallback(
    async (fileId: string) => {
      try {
        setError(null);
        // Fully use local backend
        await api.mediaServer.deleteFile(fileId, currentUser?.id, currentUser?.role);
        
        await loadFiles();
      } catch (err: unknown) {
        const errorMsg = getErrorMessage(err, "Delete failed");
        setError(errorMsg);
        console.error("Delete error:", err);
        throw err;
      }
    },
    [loadFiles, files]
  );

  const loadStats = useCallback(async () => {
    try {
      setError(null);
      
      // We compute it from local backend
      let currentFiles = files;
      if (currentFiles.length === 0) {
        const mData = await api.mediaServer.listFiles().catch(() => ({ files: [] }));
        currentFiles = mData.files.map((f: any) => ({
          file_size: f.size,
          file_type: f.fileType
        })) as any;
      }

      currentFiles.forEach((file) => {
        total_size += Number(file.file_size);
        file_types[file.file_type] = (file_types[file.file_type] || 0) + 1;
        file_type_sizes[file.file_type] =
          (file_type_sizes[file.file_type] || 0) + Number(file.file_size);
      });

      const newStats = {
        total_files: currentFiles.length,
        total_size,
        file_types,
        file_type_sizes,
      };

      setStats(newStats);
      return newStats;
    } catch (err: unknown) {
      const errorMsg = getErrorMessage(err, "Failed to load stats");
      setError(errorMsg);
      console.error("Failed to load stats:", err);
      return null;
    }
  }, [files]);

  return {
    files,
    loading,
    error,
    stats,
    loadFiles,
    uploadFile,
    downloadFile,
    deleteFile,
    loadStats,
  };
}
